// ── Backward-compatible flat list (primary codes only) ──
export interface ICD10Entry { code: string; description: string; commonName?: string; specialty?: string; }

export const ICD10_DATABASE: ICD10Entry[] = ICD_CONDITIONS.map(c => ({
  code: c.primary_code,
  description: c.primary_description,
  commonName: c.condition_name,
  specialty: c.specialty,
}));

export const searchICD10 = (query: string): ICD10Entry[] => {
  if (!query || query.length < 2) return [];
  const q = query.toLowerCase();
  const seen = new Set<string>();
  const results: ICD10Entry[] = [];
  for (const c of ICD_CONDITIONS) {
    const hit = c.primary_code.toLowerCase().includes(q)
      || c.condition_name.toLowerCase().includes(q)
      || c.primary_description.toLowerCase().includes(q)
      || c.keywords.some(k => k.toLowerCase().includes(q));
    if (hit && !seen.has(c.primary_code)) {
      seen.add(c.primary_code);
      results.push({ code: c.primary_code, description: c.primary_description, commonName: c.condition_name, specialty: c.specialty });
    }
    if (results.length >= 12) break;
  }
  return results;
};

export const getConditionByCode = (code: string): ICDCondition | undefined =>
  ICD_CONDITIONS.find(c => c.primary_code === code || c.variants.some(v => v.code === code));

export const getConditionByName = (name: string): ICDCondition | undefined => {
  const q = name.toLowerCase();
  return ICD_CONDITIONS.find(c =>
    c.condition_name.toLowerCase().includes(q) || c.keywords.some(k => k.toLowerCase().includes(q)));
};

export interface ICDSuggestion {
  condition: ICDCondition;
  confidence: number;
  matchReason: string;
}

export const suggestICD = (query: string, maxResults = 5): ICDSuggestion[] => {
  if (!query || query.length < 2) return [];
  const q = query.toLowerCase();
  const scored: ICDSuggestion[] = [];
  for (const c of ICD_CONDITIONS) {
    let score = 0; let reason = '';
    if (c.condition_name.toLowerCase() === q) { score = 1.0; reason = 'Exact match'; }
    else if (c.condition_name.toLowerCase().startsWith(q)) { score = 0.9; reason = 'Name starts with query'; }
    else if (c.condition_name.toLowerCase().includes(q)) { score = 0.8; reason = 'Name contains query'; }
    else if (c.primary_code.toLowerCase().includes(q)) { score = 0.85; reason = 'ICD code match'; }
    else if (c.primary_description.toLowerCase().includes(q)) { score = 0.75; reason = 'Description match'; }
    else if (c.keywords.some(k => k.toLowerCase().includes(q))) { score = 0.65; reason = 'Keyword/Hinglish match'; }
    if (score > 0) scored.push({ condition: c, confidence: score, matchReason: reason });
  }
  return scored.sort((a, b) => b.confidence - a.confidence).slice(0, maxResults);
};